     1→import { Switch, Route, Router as WouterRouter } from "wouter";
     2→import { QueryClient, QueryClientProvider } from "@tanstack/react-query";
     3→import { Toaster } from "@/components/ui/toaster";
     4→import { TooltipProvider } from "@/components/ui/tooltip";
     5→
     6→import Login from "./pages/login";
     7→import Dashboard from "./pages/dashboard";
     8→import Fonti from "./pages/fonti";
     9→import Eventi from "./pages/eventi";
    10→import Prompts from "./pages/prompt";
    11→import NewsletterList from "./pages/newsletter";
    12→import Templates from "./pages/template";
    13→import Impostazioni from "./pages/impostazioni";
    14→import Utenti from "./pages/utenti";
    15→import NotFound from "./pages/not-found";
    16→
    17→const queryClient = new QueryClient({
    18→  defaultOptions: {
    19→    queries: {
    20→      retry: false,
    21→      refetchOnWindowFocus: false,
    22→    },
    23→  },
    24→});
    25→
    26→function Router() {
    27→  return (
    28→    <Switch>
    29→      <Route path="/login" component={Login} />
    30→      <Route path="/" component={Dashboard} />
    31→      <Route path="/dashboard" component={Dashboard} />
    32→      <Route path="/fonti" component={Fonti} />
    33→      <Route path="/eventi" component={Eventi} />
    34→      <Route path="/prompt" component={Prompts} />
    35→      <Route path="/newsletter" component={NewsletterList} />
    36→      <Route path="/template" component={Templates} />
    37→      <Route path="/impostazioni" component={Impostazioni} />
    38→      <Route path="/utenti" component={Utenti} />
    39→      <Route component={NotFound} />
    40→    </Switch>
    41→  );
    42→}
    43→
    44→function App() {
    45→  return (
    46→    <QueryClientProvider client={queryClient}>
    47→      <TooltipProvider>
    48→        <WouterRouter base={import.meta.env.BASE_URL.replace(/\/$/, "")}>
    49→          <Router />
    50→        </WouterRouter>
    51→        <Toaster />
    52→      </TooltipProvider>
    53→    </QueryClientProvider>
    54→  );
    55→}
    56→
    57→export default App;
    58→

