        <Button className="shadow-md" onClick={() => setIsModalOpen(true)}>
          <Plus className="w-4 h-4 mr-2" />
          Nuovo Template
        </Button>
      </div>

      <TemplateModal isOpen={isModalOpen} onClose={() => setIsModalOpen(false)} />

